import React, { useState, useEffect } from 'react';
import { partnerService } from '../services/api';
import { Package, Plus, X, Search } from 'lucide-react';

const fmt = (n) => new Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', minimumFractionDigits: 2 }).format(n || 0);

function PartnerProducts() {
  const [products, setProducts]         = useState([]);
  const [loading, setLoading]           = useState(true);
  const [showModal, setShowModal]       = useState(false);
  const [selectedProduct, setSelected] = useState(null);
  const [buyerEmail, setBuyerEmail]     = useState('');
  const [notes, setNotes]               = useState('');
  const [blockingError, setBlocking]    = useState('');
  const [creating, setCreating]         = useState(false);

  useEffect(() => { loadProducts(); }, []);

  const loadProducts = async () => {
    try {
      setLoading(true);
      const r = await partnerService.getProducts();
      setProducts(r.data);
    } catch { console.error('Error loading products'); }
    finally { setLoading(false); }
  };

  const openModal = (product) => {
    setSelected(product);
    setBuyerEmail(''); setNotes(''); setBlocking('');
    setShowModal(true);
  };

  const closeModal = () => {
    setShowModal(false); setSelected(null);
    setBuyerEmail(''); setNotes(''); setBlocking('');
  };

  useEffect(() => {
    const check = async () => {
      if (!buyerEmail || !buyerEmail.includes('@') || !selectedProduct) { setBlocking(''); return; }
      try {
        const r = await partnerService.getBuyers();
        const existing = r.data.find(b => b.email.toLowerCase() === buyerEmail.toLowerCase());
        if (existing) {
          const can = await partnerService.canSellToBuyer(selectedProduct.productId, existing.userId);
          setBlocking(can.data.canSell ? '' : 'This buyer has already purchased this product');
        } else { setBlocking(''); }
      } catch { setBlocking(''); }
    };
    const t = setTimeout(check, 500);
    return () => clearTimeout(t);
  }, [buyerEmail, selectedProduct]);

  const handleCreateSale = async (e) => {
    e.preventDefault();
    if (!buyerEmail || !buyerEmail.includes('@')) { alert('Please enter a valid buyer email'); return; }
    if (blockingError) { alert(blockingError); return; }
    try {
      setCreating(true);
      const r = await partnerService.getBuyers();
      let buyerId = null;
      const existing = r.data.find(b => b.email.toLowerCase() === buyerEmail.toLowerCase());
      if (existing) {
        buyerId = existing.userId;
      } else {
        const reg = await fetch('http://localhost:5261/api/auth/register', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ fullName: buyerEmail.split('@')[0], email: buyerEmail, password: 'TempPassword@123', userRole: 'Buyer', phoneNumber: '', companyName: '', address: '' })
        });
        if (!reg.ok) throw new Error('Failed to create buyer');
        const nb = await reg.json();
        buyerId = nb.userId;
      }
      await partnerService.createSale({ productId: selectedProduct.productId, buyerId, notes });
      alert('Sale created successfully!');
      closeModal();
      loadProducts();
    } catch (err) {
      alert(err.response?.data?.message || 'Failed to create sale');
    } finally { setCreating(false); }
  };

  if (loading) return <div style={{ display:'flex', justifyContent:'center', alignItems:'center', minHeight:'100vh', color:'#64748b' }}>Loading products...</div>;

  return (
    <div style={{ padding: '2rem', background: '#f1f5f9', minHeight: '100vh' }}>
      <h1 style={{ fontSize: '2rem', fontWeight: '700', color: '#1e293b', marginBottom: '0.25rem' }}>Available Products</h1>
      <p style={{ color: '#64748b', marginBottom: '2rem' }}>Browse and sell products to earn commission</p>

      {products.length === 0 ? (
        <div style={{ textAlign: 'center', padding: '4rem 2rem', background: 'white', borderRadius: '12px', color: '#94a3b8' }}>
          <Package size={48} style={{ margin: '0 auto 1rem', opacity: 0.3 }} />
          <p style={{ fontSize: '1.1rem', fontWeight: '600', color: '#64748b' }}>No Products Available</p>
          <p style={{ fontSize: '0.9rem' }}>There are no products available for sale at the moment.</p>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '1.25rem' }}>
          {products.map(p => (
            <div key={p.productId} style={{ background: 'white', borderRadius: '14px', padding: '1.5rem', boxShadow: '0 1px 3px rgba(0,0,0,0.07)', display: 'flex', flexDirection: 'column', transition: 'transform 0.2s, box-shadow 0.2s' }}
              onMouseEnter={e => { e.currentTarget.style.transform='translateY(-3px)'; e.currentTarget.style.boxShadow='0 8px 24px rgba(0,0,0,0.1)'; }}
              onMouseLeave={e => { e.currentTarget.style.transform='translateY(0)'; e.currentTarget.style.boxShadow='0 1px 3px rgba(0,0,0,0.07)'; }}>

              {/* Card Header */}
              <div style={{ display: 'flex', alignItems: 'flex-start', gap: '1rem', marginBottom: '1rem' }}>
                <div style={{ width: '52px', height: '52px', background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', borderRadius: '14px', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                  <Package size={24} color="white" />
                </div>
                <div style={{ flex: 1 }}>
                  <h3 style={{ fontWeight: '700', color: '#1e293b', fontSize: '1.1rem', margin: '0 0 0.2rem' }}>{p.productName}</h3>
                  <p style={{ fontSize: '1.35rem', fontWeight: '700', color: '#2563eb', margin: 0 }}>{fmt(p.price)}</p>
                </div>
              </div>

              {/* Description */}
              <p style={{ color: '#64748b', fontSize: '0.875rem', lineHeight: '1.6', marginBottom: '1rem', flex: 1 }}>
                {p.description || 'No description'}
              </p>

              {/* Details */}
              <div style={{ background: '#f8fafc', borderRadius: '8px', padding: '0.875rem', marginBottom: '1rem' }}>
                {[
                  { label: 'Admin:', value: p.adminName || 'N/A', bold: true },
                  { label: 'Commission:', value: `${p.commissionPercentage}%`, color: '#16a34a' },
                  { label: 'You Earn:', value: fmt(p.price * (p.commissionPercentage / 100)), color: '#16a34a' },
                ].map(row => (
                  <div key={row.label} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.4rem' }}>
                    <span style={{ fontSize: '0.85rem', color: '#94a3b8' }}>{row.label}</span>
                    <span style={{ fontSize: '0.875rem', fontWeight: row.bold ? '700' : '600', color: row.color || '#1e293b' }}>{row.value}</span>
                  </div>
                ))}
              </div>

              {/* CTA */}
              <button onClick={() => openModal(p)} style={{
                width: '100%', padding: '0.75rem',
                background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                color: 'white', border: 'none', borderRadius: '10px',
                fontWeight: '600', fontSize: '0.95rem', cursor: 'pointer',
                display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem',
                transition: 'opacity 0.2s'
              }}
              onMouseEnter={e => e.currentTarget.style.opacity='0.9'}
              onMouseLeave={e => e.currentTarget.style.opacity='1'}>
                <Plus size={18} /> Create Sale
              </button>
            </div>
          ))}
        </div>
      )}

      {/* Sale Modal */}
      {showModal && selectedProduct && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', display:'flex', alignItems:'center', justifyContent:'center', zIndex:1000, padding:'1rem' }}
          onClick={closeModal}>
          <div style={{ background:'white', borderRadius:'16px', width:'100%', maxWidth:'480px', maxHeight:'90vh', overflowY:'auto' }} onClick={e => e.stopPropagation()}>
            {/* Modal Header */}
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'1.5rem', borderBottom:'1px solid #f1f5f9' }}>
              <h2 style={{ fontSize:'1.2rem', fontWeight:'700', color:'#1e293b', margin:0 }}>Create Sale — {selectedProduct.productName}</h2>
              <button onClick={closeModal} style={{ background:'none', border:'none', cursor:'pointer', color:'#94a3b8', display:'flex' }}><X size={22}/></button>
            </div>

            <div style={{ padding:'1.5rem' }}>
              {blockingError && buyerEmail && (
                <div style={{ background:'#fef2f2', border:'1px solid #fecaca', color:'#dc2626', padding:'0.75rem 1rem', borderRadius:'8px', marginBottom:'1rem', fontSize:'0.875rem' }}>
                  {blockingError}
                </div>
              )}

              {/* Product Info */}
              <div style={{ background:'#f8fafc', borderRadius:'10px', padding:'1rem', marginBottom:'1.5rem' }}>
                <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'0.5rem' }}>
                  <span style={{ color:'#64748b', fontSize:'0.9rem' }}>Price:</span>
                  <span style={{ fontWeight:'700', color:'#16a34a', fontSize:'1.1rem' }}>{fmt(selectedProduct.price)}</span>
                </div>
                <div style={{ display:'flex', justifyContent:'space-between' }}>
                  <span style={{ color:'#64748b', fontSize:'0.9rem' }}>Your Commission ({selectedProduct.commissionPercentage}%):</span>
                  <span style={{ fontWeight:'700', color:'#16a34a', fontSize:'1.1rem' }}>{fmt(selectedProduct.price * (selectedProduct.commissionPercentage / 100))}</span>
                </div>
              </div>

              <form onSubmit={handleCreateSale}>
                <div style={{ marginBottom:'1.25rem' }}>
                  <label style={{ display:'block', fontWeight:'600', color:'#374151', fontSize:'0.875rem', marginBottom:'0.5rem' }}>Buyer Email *</label>
                  <div style={{ position:'relative' }}>
                    <Search size={18} color="#94a3b8" style={{ position:'absolute', left:'0.875rem', top:'50%', transform:'translateY(-50%)', pointerEvents:'none' }} />
                    <input type="email" value={buyerEmail} onChange={e => setBuyerEmail(e.target.value)} placeholder="Enter buyer email address..." required
                      style={{ width:'100%', padding:'0.75rem 0.875rem 0.75rem 2.75rem', border:`1px solid ${blockingError && buyerEmail ? '#fca5a5' : '#e2e8f0'}`, borderRadius:'8px', fontSize:'0.95rem', outline:'none', boxSizing:'border-box' }}
                      onFocus={e => { if (!blockingError) e.target.style.borderColor='#667eea'; }}
                      onBlur={e => { if (!blockingError) e.target.style.borderColor='#e2e8f0'; }} />
                  </div>
                  <p style={{ fontSize:'0.75rem', color:'#94a3b8', marginTop:'0.35rem' }}>New buyers will be created automatically.</p>
                </div>

                <div style={{ marginBottom:'1.5rem' }}>
                  <label style={{ display:'block', fontWeight:'600', color:'#374151', fontSize:'0.875rem', marginBottom:'0.5rem' }}>Notes (Optional)</label>
                  <textarea value={notes} onChange={e => setNotes(e.target.value)} placeholder="Add any notes about this sale..." rows={4}
                    style={{ width:'100%', padding:'0.75rem', border:'1px solid #e2e8f0', borderRadius:'8px', fontSize:'0.95rem', outline:'none', resize:'vertical', fontFamily:'inherit', boxSizing:'border-box' }}
                    onFocus={e => e.target.style.borderColor='#667eea'} onBlur={e => e.target.style.borderColor='#e2e8f0'} />
                </div>

                <div style={{ display:'flex', gap:'0.75rem' }}>
                  <button type="button" onClick={closeModal} style={{ flex:1, padding:'0.75rem', background:'white', color:'#64748b', border:'1px solid #e2e8f0', borderRadius:'8px', fontWeight:'600', cursor:'pointer' }}>Cancel</button>
                  <button type="submit" disabled={creating || !!blockingError} style={{ flex:1, padding:'0.75rem', background: (creating || blockingError) ? '#e2e8f0' : 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', color: (creating || blockingError) ? '#94a3b8' : 'white', border:'none', borderRadius:'8px', fontWeight:'600', cursor: (creating || blockingError) ? 'not-allowed' : 'pointer' }}>
                    {creating ? 'Creating...' : 'Create Sale'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default PartnerProducts;
